-- === 考公模块 (module_id=1) ===
INSERT INTO `post` (`user_id`, `module_id`, `title`, `content`, `view_count`, `create_time`) VALUES
(2, 1, '国考行测如何从65分提到75分？分享我的备考经历', '大家好，我是张三，去年国考行测65分，今年经过系统复习拿到了75分，分享一下我的备考经验：\n\n1. 资料分析一定要拿满分\n资料分析是最容易提分的模块，掌握速算技巧后准确率可以到95%以上。推荐每天做2篇真题资料分析。\n\n2. 言语理解靠积累\n每天读一篇人民日报评论，培养语感。做题时注意找主旨句和关键词。\n\n3. 判断推理多练图推\n图形推理是很多人的弱项，我的方法是把近5年的真题图推全做一遍，总结规律。\n\n4. 数量关系学会取舍\n数量关系15道题，建议先做简单的10道，剩下的猜。不要在难题上浪费时间。\n\n5. 常识判断靠平时\n多看新闻联播，关注时政。法律、科技、人文都要涉猎。\n\n有问题可以交流！', 156, '2026-04-02 10:30:00'),
(5, 1, '省考申论大作文怎么写？求指导', '马上要参加省考了，申论大作文总是写不好，每次都在40分左右徘徊。\n\n我的主要问题：\n1. 不知道怎么确定立意\n2. 分论点展开总是很空洞\n3. 字数凑不够1000字\n\n有没有大佬分享一下申论大作文的写法？特别是如何找准立意、如何充实论据？\n\n另外想问一下，申论有没有必要报班？自学可以提高吗？', 89, '2026-04-05 14:20:00'),
(9, 1, '上岸学长分享：选岗位真的比笔试更重要', '去年成功上岸某市直机关，回头看最关键的一步其实是选岗位。\n\n我的分数并不高，行测72，申论68，总分140。这个分数在热门岗位根本没有竞争力，但我选了一个偏远乡镇的三不限岗位，最终以第一名进面。\n\n选岗建议：\n1. 先确定自己的分数区间（参考往年分数线）\n2. 优先选报考人数少的岗位\n3. 三不限岗位虽然竞争大，但分数线相对可预估\n4. 不要盲目追求大城市核心岗位\n5. 乡镇岗位工作2-3年可以遴选调回\n\n当然，每个人情况不同，量力而行。', 203, '2026-04-08 09:15:00'),

-- === 考研模块 (module_id=2) ===
(3, 2, '双非逆袭985经验帖：从备考到录取全过程', '先说结果：本科双非（普通二本），今年考上了华中科技大学计算机学硕，初试总分398分（政治72，英一78，数一128，专业课120）。\n\n时间线：\n- 3-6月：数学基础阶段，看张宇基础30讲+做1000题\n- 7-8月：数学强化+英语真题+专业课开始\n- 9-10月：政治开始+数学真题+专业课真题\n- 11-12月：全面冲刺，模拟考试\n\n几个关键建议：\n1. 数学是王道，一定要打好基础\n2. 英语真题至少做3遍\n3. 政治不用太早开始，9月足够\n4. 专业课找目标院校学长要资料\n5. 坚持最重要，中途放弃的太多了\n\n大家有问题可以问我！', 312, '2026-04-03 11:00:00'),
(7, 2, '考研择校：如何选择适合自己的院校和专业？', '考研择校是个大问题，很多同学一上来就想冲清北复交，结果准备不充分名落孙山。\n\n我的择校思路：\n\n第一步：确定专业方向\n- 考虑就业前景\n- 考虑自己的兴趣\n- 考虑跨专业的难度\n\n第二步：确定院校层次\n- 根据自身实力合理定位\n- 参考往年录取分数线\n- 关注报录比\n\n第三步：细化选择\n- 看导师方向\n- 看课题组情况\n- 看往届就业去向\n\n几个信息渠道推荐：\n- 研招网：官方数据\n- 各校研究生院官网：招生简章\n- 考研论坛：往届经验\n- 学长学姐：一手信息', 178, '2026-04-06 16:30:00'),
(10, 2, '考研英语一阅读理解解题技巧总结', '英语一阅读是拉分大项，满分40分。我考了34分，总结几个实用技巧：\n\n1. 先看题目再看文章\n带着问题读文章效率更高，可以快速定位。\n\n2. 注意转折词\n但是(but/however/yet)后面的内容往往是答案所在。\n\n3. 主旨题看首尾段\n文章首段和尾段通常包含中心思想。\n\n4. 推断题注意"合理推断"\n答案不会太离谱，选最贴近原文的。\n\n5. 态度题关注情感词\n作者态度一般不会极端，排除绝对化选项。\n\n6. 每天保持阅读手感\n考前一定不能断练，每天至少做1-2篇。', 145, '2026-04-09 20:00:00'),

-- === 四级模块 (module_id=3) ===
(6, 3, '四级裸考能过吗？分享我424→530的逆袭', '第一次四级考试424分，差1分没过，当时心态直接崩了。\n\n第二次认真准备了两个月，最终530分通过。说说我做了什么：\n\n听力（提升最大的部分）：\n- 每天听VOA慢速英语30分钟\n- 做真题听力时先裸听，再对照原文精听\n- 总结高频场景词汇\n\n阅读：\n- 每天做1篇真题阅读\n- 重点练信息匹配题（分值大且好提分）\n- 积累核心词汇\n\n写作和翻译：\n- 背10个万能句型\n- 练习5篇真题作文\n- 翻译重点练中国文化类话题\n\n建议：千万不要裸考！认真准备两个月，过四级真的不难。', 267, '2026-04-04 08:45:00'),
(8, 3, '四级听力总是跟不上怎么办？', '每次做四级听力都感觉说得太快了，还没反应过来就到下一题了。\n\n我目前的情况：\n- 词汇量大概3500左右\n- 阅读部分还行，能做对60%\n- 听力只能对30%左右\n\n试过的方法：\n1. 听BBC/VOA，但感觉太难了完全听不懂\n2. 看美剧练听力，好像没什么效果\n3. 做真题听力，错太多打击信心\n\n有没有更好的方法？比较适合基础差的那种。\n另外有没有推荐的听力APP？', 134, '2026-04-07 19:30:00'),
(4, 3, '分享一些四级高频词汇，直接背就完了', '整理了四级真题中出现频率最高的200个词汇，按主题分类：\n\n【教育类】\n- enrollment 注册/招生\n- curriculum 课程\n- semester 学期\n- discipline 学科/纪律\n- scholarship 奖学金\n\n【科技类】\n- innovation 创新\n- artificial intelligence 人工智能\n- sustainable 可持续的\n- renewable 可再生的\n\n【社会类】\n- poverty 贫困\n- inequality 不平等\n- urbanization 城市化\n- demographic 人口统计的\n\n【经济类】\n- inflation 通货膨胀\n- recession 衰退\n- revenue 收入\n- commodity 商品\n\n（篇幅有限只列了一部分，完整版可以私信我）', 198, '2026-04-11 12:00:00'),

-- === 六级模块 (module_id=4) ===
(3, 4, '六级翻译怎么拿高分？这些套路必须知道', '六级翻译106.5分，每年考的都是中国文化、经济、社会话题。\n\n高分策略：\n\n1. 积累常见话题词汇\n中国传统文化、经济发展、科技创新、教育改革这四大类必背。\n\n2. 句式多样化\n不要全用简单句，适当使用：\n- 定语从句\n- 被动语态\n- 分词短语\n- 强调句\n\n3. 不会的词用近义词替换\n比如"一带一路"不会写，可以说"the Silk Road Economic Belt and the 21st-Century Maritime Silk Road"。\n\n4. 注意逻辑连接\n用firstly/moreover/in addition等连接词让翻译更通顺。\n\n多练真题翻译，每次练完对照范文找差距。', 167, '2026-04-06 10:20:00'),
(11, 4, '六级刷分有必要吗？500分和600分差别大吗？', '我六级第一次考了510分，想刷到600+。\n\n想问问大家：\n1. 六级分数在求职时真的重要吗？\n2. 500分和600分的实际差距在哪里？\n3. 值不值得花时间刷分？\n\n我目前大三，时间比较紧，还要准备考研。如果六级分数对求职帮助不大的话，我想把时间用在考研上。\n\n有过来人能分享一下经验吗？', 98, '2026-04-12 15:40:00'),

-- === 雅思模块 (module_id=5) ===
(8, 5, '雅思首考7.0经验分享（备考3个月）', '背景：六级580分，备考3个月，雅思首考总分7.0（L7.5 R7.5 W6.0 S6.5）\n\n各科备考方法：\n\n听力（7.5）：\n- 剑桥真题4-17全做了2遍\n- 精听每天1小时\n- Section4学术讲座是难点，多练\n\n阅读（7.5）：\n- 掌握定位技巧是关键\n- 平行阅读法处理匹配题\n- 判断题注意NOT GIVEN和FALSE的区别\n\n写作（6.0）：\n- 大作文背了15个话题的思路\n- 小作文练了各种图表的写法\n- 考前找了外教批改3篇\n\n口语（6.5）：\n- 准备了当季所有Part2话题\n- 每天对镜练习30分钟\n- 注意流利度和发音\n\n写作是我的弱项，下次想刷到7.0+重点攻写作。', 234, '2026-04-05 13:00:00'),
(9, 5, '雅思口语Part2万能素材整理', '整理了一些Part2的万能素材，一个故事可以套很多话题：\n\n【万能人物故事】\n可以用在：a person you admire / a friend / someone who helped you / someone who is good at their job\n\n准备一个关于你朋友/老师的故事，包含：\n- 认识的经过\n- 一件印象深刻的事\n- 对你的影响\n\n【万能旅行经历】\n可以用在：a trip / a place you visited / an outdoor activity / a happy experience\n\n准备一个旅行故事：\n- 去了哪里、和谁去的\n- 做了什么特别的事\n- 感受如何\n\n【万能学习经历】\n可以用在：a skill you learned / a course / a challenge / an achievement\n\n这三个素材基本可以覆盖80%的Part2话题，灵活运用即可。', 189, '2026-04-10 17:20:00'),

-- === 托福模块 (module_id=6) ===
(7, 6, '托福110+经验：各科突破方法详解', '背景：英专，本来英语底子不错，但第一次托福只有98。后来针对性准备2个月，第二次考了112（R30 L28 S26 W28）。\n\n阅读满分心得：\n- 托福阅读比雅思更需要逻辑分析能力\n- 词汇题直接选，不用回原文\n- 推断题和修辞目的题多练\n- 六选三总结题注意排除细节选项\n\n听力28分心得：\n- 笔记不要什么都记，记结构和关键信息\n- conversation注意语气变化\n- lecture注意example和对比\n\n口语26分：\n- 独立口语背模板+练计时\n- 综合口语关键是听懂+有条理转述\n\n写作28分：\n- 独立写作要有具体例子\n- 综合写作忠实于听力内容', 156, '2026-04-07 11:30:00'),
(10, 6, '托福和雅思到底考哪个？对比分析', '最近在纠结考托福还是雅思，做了一番研究分享给大家：\n\n【适合考托福的情况】\n- 去北美（美国、加拿大）留学\n- 习惯机考\n- 听力能力较强\n- 喜欢客观题（选择题为主）\n\n【适合考雅思的情况】\n- 去英联邦国家（英国、澳洲等）留学\n- 更喜欢纸笔考或与人对话\n- 写作能力相对更好\n- 不适应长时间机考\n\n【分数换算参考】\n- 雅思7.0 ≈ 托福94-101\n- 雅思7.5 ≈ 托福102-109\n- 雅思8.0 ≈ 托福110-114\n\n【我的选择】\n最终选了托福，因为我目标学校在美国，而且我听力比较好。\n\n大家根据自己的目标院校和个人强项来选择就好。', 178, '2026-04-13 09:45:00'),

-- === 计算机等级模块 (module_id=7) ===
(6, 7, '计算机二级MS Office高级应用备考攻略', '刚考完计算机二级MS Office，分数92分，分享备考经验。\n\n考试内容：\n- 选择题20分（计算机基础+Office知识）\n- Word操作题30分\n- Excel操作题30分\n- PPT操作题20分\n\n备考建议：\n\n1. 选择题：刷题库就行，重点背计算机基础知识。推荐未来教育的题库。\n\n2. Word部分：\n- 重点练样式设置、目录生成\n- 邮件合并是必考\n- 多级列表设置\n\n3. Excel部分（最难，分值最高）：\n- VLOOKUP、IF、COUNTIF必须熟练\n- 数据透视表一定要会\n- 条件格式和数据有效性\n\n4. PPT部分：\n- 母版设置\n- 动画和切换效果\n- SmartArt图形\n\n建议备考时间：2-3周，每天练2小时。', 245, '2026-04-04 15:00:00'),
(4, 7, '计算机二级Python考试经历分享', '上周刚考完计算机二级Python，成绩还没出来，先分享一下考试经历。\n\n选择题部分：\n- 比想象中简单，基本都是教材上的知识\n- 有几道关于turtle库的题需要注意\n- 二进制转换必考\n\n操作题部分：\n- 第一题是基础编程，写了一个成绩统计程序\n- 第二题用了jieba分词和wordcloud生成词云\n- 第三题是文件操作，读取CSV做数据处理\n\n整体感觉：\n- 如果有Python基础，准备1-2周足够\n- 如果零基础，建议至少1个月\n- 重点掌握字符串操作、列表操作、文件读写\n- turtle库和第三方库的基本用法要了解\n\n推荐刷未来教育或小黑课堂的题库。', 167, '2026-04-09 18:30:00'),
(11, 7, '请问计算机三级网络技术难吗？', '已经过了二级，想继续考三级网络技术。\n\n想问问考过的同学：\n1. 三级网络技术和二级相比难度差距大吗？\n2. 需要多长时间准备？\n3. 有没有推荐的学习资料？\n4. 这个证对找工作有帮助吗？\n\n我目前是计算机专业大二学生，有一定的网络基础（学过计算机网络课程）。', 76, '2026-04-14 20:15:00');
